import { Link, useNavigate } from "react-router-dom";
// import { techStacks } from "../datasets/stackData";
import { useEffect, useState } from "react";
// import '';

function SelectStack({setSelected, selected}) {
  const navigate = useNavigate();
  const [techStacks, setTechStacks] = useState([]);

  useEffect(() => {
    fetch("http://127.0.0.1:5000/stacks")
    .then((result) => result.json())
    .then((data) => setTechStacks(data))
  }, [])

  const handleSelectStack = (stackName) => {
    setSelected(stackName);
    navigate(`/select/${stackName}`)
  }
  return (
    <div className='h-screen flex justify-center items-center'>
      <div className="text-center w-[48%]"> 
        <div className="mb-10">
            <h1 className="text-white font-bold text-4xl mb-2"> Choose Your Stack</h1>
            <p className="text-[#7589a3] text-base"> Pick a technology to get quizzed on</p>
        </div>
        <div className="grid grid-cols-2 gap-4">
            {/* 
             set the selected state with the stack name onclick
             pass it back to the parent/root (prop drilling)
              set pass to te parent/ root {} prop drilling onclinvk
            */}
            {
                techStacks.map((stack, index) => (
                    <div key={index} onClick={() => handleSelectStack(stack.id)} className="bg-[#151923] border border-[#7589a3] text-center py-8 px-5 rounded rounded-lg tansition delay-150 duration-300 ease-in-out hover:cursor-pointer hover:shadow-xl/20 hover:shadow-[#7056f6] hover:border-[#7056f6]">
                        <div className="text-[#7056f6] font-bold text-xl mb-3"> {'</>'} </div>
                        <h1 className="text-white text-xl mb-3">{stack.name}</h1>
                        <p className="text-[#7589a3] text-base"> {stack.description} </p>
                    </div>
                ))
            }

        </div>
        <Link to="/"> 
            <p className="inline-block text-[#7589a3] text-base hover:text-[#7056f6] hover:cursor-pointer mt-6"> Back to Home</p>
        </Link>
      </div>
    </div>
  );
}

export default SelectStack;
